SELECT site_name
FROM sites
WHERE last_update_date = (
    SELECT MAX(last_update_date) FROM sites
);

SELECT layer_description, SUM(artifact_count) AS total_artifacts
FROM chronologies
GROUP BY layer_description;

SELECT COUNT(chronology_id) AS chronology_count
FROM chronologies
WHERE site_id = (SELECT site_id FROM sites WHERE site_name = 'Gordion');

SELECT site_name
FROM sites
ORDER BY site_name ASC;

SELECT COUNT(artifact_count) AS number_of_artifacts
FROM chronologies
WHERE site_id = 1 AND layer_description = 'Topsoil';
